@Service
@Slf4ArgsConstructor
class ProductService {

    private static final String PRODUCT_INDEX_NAME = "products";
    private final RestHighLevelClient esClient;
    private final ObjectMapper objectMapper;

    public String indexProduct(Product product) throws IOException {
        if (product.getId() == null) {
            product.setId(UUID.randomUUID().toString());
        }
        IndexRequest request = new IndexRequest(PRODUCT_INDEX_NAME)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), XContentType.JSON);

        IndexResponse response = esClient.index(request, RequestOptions.DEFAULT);
        log.info("Indexed product with ID: {}", response.getId());
        return response.getId();
    }

    public SearchResult searchProducts(
            String query,
            List<String> categories,
            List<String> brands,
            Double minPrice,
            Double maxPrice,
            int page,
            int size) throws IOException {

        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX_NAME);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // 1. Full-text search
        if (query != null && !query.trim().isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(query, "name^3", "description")); // Boost name field
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery()); // If no query, match all
        }

        // 2. Faceted navigation filters
        if (categories != null && !categories.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category.keyword", categories));
        }
        if (brands != null && !brands.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", brands));
        }
        if (minPrice != null || maxPrice != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price")
                    .gte(minPrice)
                    .lte(maxPrice));
        }

        sourceBuilder.query(boolQuery);

        // 3. Pagination
        sourceBuilder.from(page * size);
        sourceBuilder.size(size);
        sourceBuilder.timeout(new TimeValue(60, TimeUnit.SECONDS));

        // 4. Sorting (optional, e.g., by price)
        sourceBuilder.sort("price", SortOrder.ASC);

        // 5. Aggregations for facets
        sourceBuilder.aggregation(AggregationBuilders.terms("categories_agg").field("category.keyword").size(10));
        sourceBuilder.aggregation(AggregationBuilders.terms("brands_agg").field("brand.keyword").size(10));
        sourceBuilder.aggregation(AggregationBuilders.range("price_ranges_agg").field("price")
                .addUnboundedFrom("0-50", 50.0)
                .addRange("50-100", 50.0, 100.0)
                .addRange("100-200", 100.0, 200.0)
                .addUnboundedTo("200+", 200.0));

        searchRequest.source(sourceBuilder);

        SearchResponse searchResponse = esClient.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            products.add(objectMapper.readValue(hit.getSourceAsString(), Product.class));
        }

        List<Facet> facets = new ArrayList<>();
        if (searchResponse.getAggregations() != null) {
            // Category Facet
            ParsedTerms categoriesAgg = searchResponse.getAggregations().get("categories_agg");
            if (categoriesAgg != null) {
                List<FacetBucket> categoryBuckets = categoriesAgg.getBuckets().stream()
                        .map(bucket -> new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount(), null, null))
                        .collect(Collectors.toList());
                facets.add(new Facet("category", categoryBuckets));
            }

            // Brand Facet
            ParsedTerms brandsAgg = searchResponse.getAggregations().get("brands_agg");
            if (brandsAgg != null) {
                List<FacetBucket> brandBuckets = brandsAgg.getBuckets().stream()
                        .map(bucket -> new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount(), null, null))
                        .collect(Collectors.toList());
                facets.add(new Facet("brand", brandBuckets));
            }

            // Price Range Facet
            ParsedRange priceRangesAgg = searchResponse.getAggregations().get("price_ranges_agg");
            if (priceRangesAgg != null) {
                List<FacetBucket> priceBuckets = priceRangesAgg.getBuckets().stream()
                        .map(bucket -> new FacetBucket(
                                bucket.getKeyAsString(),
                                bucket.getDocCount(),
                                bucket.getFrom() != null ? (Double) bucket.getFrom() : null,
                                bucket.getTo() != null ? (Double) bucket.getTo() : null
                        ))
                        .collect(Collectors.toList());
                facets.add(new Facet("price", priceBuckets));
            }
        }

        long totalHits = searchResponse.getHits().getTotalHits().value;
        long totalPages = (long) Math.ceil((double) totalHits / size);

        return new SearchResult(products, totalHits, facets, page, size, totalPages);
    }
}

@Service
@Slf4ArgsConstructor
class SearchQueryService {

    private static final String SEARCH_QUERY_INDEX_NAME = "search_queries";
    private final RestHighLevelClient esClient;
    private final ObjectMapper objectMapper;

    public String logSearchQuery(String queryText, String userId) throws IOException {
        SearchQuery searchQuery = new SearchQuery(UUID.randomUUID().toString(), queryText, LocalDateTime.now(), userId);

        IndexRequest request = new IndexRequest(SEARCH_QUERY_INDEX_NAME)
                .id(searchQuery.getId())
                .source(objectMapper.writeValueAsString(searchQuery), XContentType.JSON);

        IndexResponse response = esClient.index(request, RequestOptions.DEFAULT);
        log.info("Logged search query with ID: {}", response.getId());
        return response.getId();
    }
}

